const { ethers } = require('ethers');

// Create a new Ethers.js instance with the desired provider
const provider = new ethers.providers.JsonRpcProvider('https://mainnet.infura.io/v3/<YOUR_PROJECT_ID>');

// Create a new Contract object from the deployed contract address and ABI
const contractAddress = '0x8626f6940e1d3a69aa7b6ce6fe12d017c5d7a9dd';
const abi = [ /* paste the ABI here */ ];
const myContract = new ethers.Contract(contractAddress, abi, provider);

// Function to handle the form submission and construct a transaction object
function handleFormSubmit() {
  const formData = document.querySelector('#form').elements;
  const txParams = {};

  // Iterate over all the input fields in the form and construct the transaction parameters
  for (let i = 0; i < formData.length; i++) {
    const input = formData[i];
    const value = input.value || null;
    txParams[input.name] = value;
  }

  // Construct a new transaction object using the constructed parameters
  const tx = myContract.getTransaction(txParams);

  // Send the transaction to the blockchain using the Ethers.js provider
  provider.sendTransaction(tx)
    .then((response) => {
      console.log('Transaction sent successfully', response);
    })
    .catch((error) => {
      console.error('Error sending transaction', error);
    });
}

